CREATE TABLE IF NOT EXISTS commerce_workflow_rules (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, rule_key TEXT NOT NULL, name TEXT NOT NULL, trigger_event TEXT NOT NULL, conditions_json TEXT NOT NULL DEFAULT '[]', actions_json TEXT NOT NULL DEFAULT '[]', active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, rule_key));
CREATE TABLE IF NOT EXISTS commerce_workflow_runs (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, rule_id TEXT, event_type TEXT NOT NULL, event_ref TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'skipped', matched INTEGER NOT NULL DEFAULT 0, actions_json TEXT NOT NULL DEFAULT '[]', result_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (rule_id) REFERENCES commerce_workflow_rules(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS loyalty_programs (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, name TEXT NOT NULL, earn_points_per_dollar INTEGER NOT NULL DEFAULT 1, redeem_cents_per_point INTEGER NOT NULL DEFAULT 1, minimum_redeem_points INTEGER NOT NULL DEFAULT 100, active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS loyalty_ledger (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, customer_id TEXT NOT NULL, order_id TEXT, points_delta INTEGER NOT NULL DEFAULT 0, reason TEXT NOT NULL DEFAULT 'adjust', note TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (customer_id) REFERENCES customer_accounts(id) ON DELETE CASCADE, FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS product_reviews (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, product_id TEXT NOT NULL, customer_id TEXT, customer_name TEXT NOT NULL DEFAULT '', customer_email TEXT NOT NULL DEFAULT '', rating INTEGER NOT NULL DEFAULT 5, title TEXT NOT NULL DEFAULT '', body TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'pending', source TEXT NOT NULL DEFAULT 'storefront', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE, FOREIGN KEY (customer_id) REFERENCES customer_accounts(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS inventory_transfers (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, from_location_id TEXT NOT NULL, to_location_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'requested', reference TEXT NOT NULL DEFAULT '', note TEXT NOT NULL DEFAULT '', items_json TEXT NOT NULL DEFAULT '[]', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, completed_at TEXT, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (from_location_id) REFERENCES inventory_locations(id) ON DELETE CASCADE, FOREIGN KEY (to_location_id) REFERENCES inventory_locations(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS idx_workflow_rules_merchant ON commerce_workflow_rules (merchant_id, active, trigger_event);
CREATE INDEX IF NOT EXISTS idx_workflow_runs_merchant ON commerce_workflow_runs (merchant_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_loyalty_programs_merchant ON loyalty_programs (merchant_id, active, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_loyalty_ledger_customer ON loyalty_ledger (merchant_id, customer_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_reviews_product ON product_reviews (merchant_id, product_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_inventory_transfers_merchant ON inventory_transfers (merchant_id, status, created_at DESC);
